/**
 * @summary Force immediate ESPN data refresh
 */
export const getForceRefreshUrl = () => {
  return `/api/admin/refresh`;
};

export const forceRefresh = async (
  forceRefreshBody: ForceRefreshBody,
  options?: RequestInit,
): Promise<RefreshResponse> => {
  return customFetch<RefreshResponse>(getForceRefreshUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(forceRefreshBody),
  });
};

export const getForceRefreshMutationOptions = <
  TError = ErrorType<ErrorResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof forceRefresh>>,
    TError,
    { data: BodyType<ForceRefreshBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof forceRefresh>>,
  TError,
  { data: BodyType<ForceRefreshBody> },
  TContext
> => {
  const mutationKey = ["forceRefresh"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof forceRefresh>>,
    { data: BodyType<ForceRefreshBody> }
  > = (props) => {
    const { data } = props ?? {};

    return forceRefresh(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type ForceRefreshMutationResult = NonNullable<
  Awaited<ReturnType<typeof forceRefresh>>
>;
export type ForceRefreshMutationBody = BodyType<ForceRefreshBody>;
export type ForceRefreshMutationError = ErrorType<ErrorResponse>;

/**
 * @summary Force immediate ESPN data refresh
 */
export const useForceRefresh = <
  TError = ErrorType<ErrorResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof forceRefresh>>,
    TError,
    { data: BodyType<ForceRefreshBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof forceRefresh>>,
  TError,
  { data: BodyType<ForceRefreshBody> },
  TContext
> => {
  return useMutation(getForceRefreshMutationOptions(options));
};

/**
 * @summary Get picks for a pool member in a tournament
 */
export const getGetMemberPicksUrl = (
  tournamentId: string,
  poolMemberId: string,
) => {
  return `/api/admin/picks/${tournamentId}/${poolMemberId}`;
};

export const getMemberPicks = async (
  tournamentId: string,
  poolMemberId: string,
  options?: RequestInit,
): Promise<GolferFieldEntry[]> => {
  return customFetch<GolferFieldEntry[]>(
    getGetMemberPicksUrl(tournamentId, poolMemberId),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getGetMemberPicksQueryKey = (
  tournamentId: string,
  poolMemberId: string,
) => {
  return [`/api/admin/picks/${tournamentId}/${poolMemberId}`] as const;
};

export const getGetMemberPicksQueryOptions = <
  TData = Awaited<ReturnType<typeof getMemberPicks>>,
  TError = ErrorType<unknown>,
>(
  tournamentId: string,
  poolMemberId: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getMemberPicks>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ??
    getGetMemberPicksQueryKey(tournamentId, poolMemberId);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getMemberPicks>>> = ({
    signal,
  }) =>
    getMemberPicks(tournamentId, poolMemberId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!(tournamentId && poolMemberId),
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getMemberPicks>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetMemberPicksQueryResult = NonNullable<
  Awaited<ReturnType<typeof getMemberPicks>>
>;
export type GetMemberPicksQueryError = ErrorType<unknown>;

/**
 * @summary Get picks for a pool member in a tournament
 */

export function useGetMemberPicks<
  TData = Awaited<ReturnType<typeof getMemberPicks>>,
  TError = ErrorType<unknown>,
>(
  tournamentId: string,
  poolMemberId: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getMemberPicks>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetMemberPicksQueryOptions(
    tournamentId,
    poolMemberId,
    options,
  );

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
